text:
{
  "formal_minutes": {
    "회의정보": {
      "project_code": "PUBLIC_MEETING_SMOKE",
      "meeting_title": "UI Theme Package Release Readiness",
      "participants": [
        "Minjun",
        "Seoyeon",
        "Doyun",
        "Hara"
      ]
    },
    "confirmed_decisions": [
      {
        "topic": "공개 릴리스 목표 시점",
        "decision": "스모크 테스트 통과를 조건으로 금요일 15:00 KST를 공개 릴리스 목표로 한다.",
        "basis": "수요일 제안에 대해 스모크 테스트 선행 필요 이의가 제기되었고 최종 결정이 정리됨."
      },
      {
        "topic": "packageName mismatch 대응 원칙",
        "decision": "packageName mismatch가 발생하면 먼저 패키지 설정을 점검하고, 계약 자체가 잘못된 경우에만 스크립트 검토를 진행한다.",
        "basis": "smoke-theme-pack.mjs에서 mismatch를 무시하자는 제안은 기각됨."
      }
    ],
    "rejected_proposals": [
      {
        "topic": "릴리스 일정",
        "proposal": "수요일 릴리스",
        "result": "기각",
        "reason": "스모크 테스트 통과가 선행 조건으로 확인됨."
      },
      {
        "topic": "검사 스크립트 처리",
        "proposal": "smoke-theme-pack.mjs에서 packageName mismatch를 무시하도록 변경",
        "result": "기각",
        "reason": "mismatch는 먼저 패키지 설정과 계약 정합성을 확인해야 한다는 방향으로 정리됨."
      }
    ],
    "internal_stretch_goals": [
      {
        "goal": "수요일 릴리스",
        "status": "내부 스트레치 목표",
        "note": "최종 공개 릴리스 확정 일정이 아님."
      }
    ],
    "non_decisions": [
      {
        "topic": "README 설치 단계 검토",
        "note": "목요일까지 가능하면 검토하자는 의견은 있었으나 담당자가 지정되지 않음."
      }
    ],
    "risks": [
      {
        "risk": "잘못된 tarball 경로가 릴리스를 지연시킬 수 있음."
      },
      {
        "risk": "README 설치 단계가 오래되었으면 릴리스 노트가 사용자에게 오해를 줄 수 있음."
      }
    ],
    "open_questions": [
      {
        "question": "최종 릴리스 승인 권한자는 누구인가?"
      },
      {
        "question": "릴리스 노트에 내부용 수요일 스트레치 목표를 언급해야 하는가?"
      }
    ]
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "스모크 테스트를 재실행하고 결과를 공유한다.",
      "due": "금요일 10:00 KST",
      "status": "확정",
      "source_certainty": "confirmed"
    },
    {
      "owner": "Doyun",
      "task": "실패 트리아지 노트를 action_items.md에 작성한다.",
      "due": "금요일 12:00 KST",
      "status": "확정",
      "source_certainty": "confirmed"
    },
    {
      "owner": "Hara",
      "task": "Minjun의 스모크 결과 공유 이후 생성된 tarball 경로를 점검한다.",
      "due": "미정",
      "status": "확정",
      "source_certainty": "confirmed"
    },
    {
      "owner": "미지정",
      "task": "README 설치 단계를 가능하면 목요일까지 검토한다.",
      "due": "목요일 가능 시",
      "status": "미배정",
      "source_certainty": "tentative"
    }
  ],
  "followup_note": {
    "next_checks": [
      "금요일 10:00 KST 기준 Minjun의 스모크 테스트 결과 공유 여부를 확인한다.",
      "스모크 결과 이후 Hara의 tarball 경로 점검 결과를 확인한다.",
      "금요일 12:00 KST 기준 Doyun의 failure triage note 작성 여부를 확인한다.",
      "README 설치 단계 검토 담당자 지정 필요 여부를 확인한다.",
      "최종 릴리스 승인 권한자 식별이 필요한지 확인한다.",
      "릴리스 노트에 수요일 내부 스트레치 목표를 언급할지 결정되었는지 확인한다."
    ],
    "do_not_invent": [
      "고객명",
      "예산 정보",
      "보안 사고",
      "프로덕션 장애",
      "법무 승인 요구",
      "미지정 owner",
      "명시되지 않은 deadline"
    ],
    "scope_guard": "본 기록은 제공된 공개용 합성 회의 메모만 기반으로 하며, 확인되지 않은 외부 사실이나 참조 출력은 사용하지 않는다."
  },
  "non_invention_rules": [
    "고객, 외부 파트너 관련 사실을 추가하지 않는다.",
    "예산 수치나 비용 승인을 추가하지 않는다.",
    "보안 사고나 운영 장애를 추가하지 않는다.",
    "법률 또는 규제 승인 요구를 추가하지 않는다.",
    "명시되지 않은 담당자와 기한을 확정 사실처럼 쓰지 않는다.",
    "확정 결정과 기각안, 내부 스트레치 목표, 리스크, 미해결 질문을 서로 혼동하지 않는다."
  ]
}
